import{_ as t,o as a,c as d,a2 as o}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 23 — Visual Mode: Line Selection","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/23-visual-mode-line.md","filePath":"chapters/23-visual-mode-line.md"}'),n={name:"chapters/23-visual-mode-line.md"};function s(i,e,l,c,r,h){return a(),d("div",null,[...e[0]||(e[0]=[o(`<h1 id="chapter-23-—-visual-mode-line-selection" tabindex="-1">Chapter 23 — Visual Mode: Line Selection <a class="header-anchor" href="#chapter-23-—-visual-mode-line-selection" aria-label="Permalink to &quot;Chapter 23 — Visual Mode: Line Selection&quot;">​</a></h1><blockquote><p><em>&quot;Line-wise selection makes editing entire lines effortless.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 10 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Line-wise visual mode selects whole lines at a time.</p><p>It is the most common visual mode for code editing.</p><hr><h1 id="line-wise-visual-mode" tabindex="-1">Line-Wise Visual Mode <a class="header-anchor" href="#line-wise-visual-mode" aria-label="Permalink to &quot;Line-Wise Visual Mode&quot;">​</a></h1><p>Press <code>V</code> (capital V) to enter line-wise visual mode.</p><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>V</code></td><td>Enter line-wise visual mode</td></tr><tr><td><code>j</code></td><td>Extend selection downward</td></tr><tr><td><code>k</code></td><td>Extend selection upward</td></tr></tbody></table><hr><h1 id="actions-on-selection" tabindex="-1">Actions on Selection <a class="header-anchor" href="#actions-on-selection" aria-label="Permalink to &quot;Actions on Selection&quot;">​</a></h1><p>Same as character-wise, but operates on whole lines:</p><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>d</code></td><td>Delete selected lines</td></tr><tr><td><code>y</code></td><td>Yank selected lines</td></tr><tr><td><code>c</code></td><td>Change selected lines</td></tr><tr><td><code>&gt;</code></td><td>Indent right</td></tr><tr><td><code>&lt;</code></td><td>Indent left</td></tr><tr><td><code>J</code></td><td>Join selected lines</td></tr><tr><td><code>=</code></td><td>Auto-indent selected lines</td></tr></tbody></table><hr><h1 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>def hello():</span></span>
<span class="line"><span>    print(&quot;Hello&quot;)</span></span>
<span class="line"><span>    print(&quot;World&quot;)</span></span>
<span class="line"><span>    return True</span></span></code></pre></div><p>Press <code>V</code> on line 2, press <code>j</code> twice:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>def hello():</span></span>
<span class="line"><span>    print(&quot;Hello&quot;)    ← selected</span></span>
<span class="line"><span>    print(&quot;World&quot;)    ← selected</span></span>
<span class="line"><span>    return True       ← selected</span></span></code></pre></div><p>Press <code>&gt;</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>def hello():</span></span>
<span class="line"><span>        print(&quot;Hello&quot;)</span></span>
<span class="line"><span>        print(&quot;World&quot;)</span></span>
<span class="line"><span>        return True</span></span></code></pre></div><hr><h1 id="switching-visual-modes" tabindex="-1">Switching Visual Modes <a class="header-anchor" href="#switching-visual-modes" aria-label="Permalink to &quot;Switching Visual Modes&quot;">​</a></h1><p>While in visual mode, you can switch:</p><table tabindex="0"><thead><tr><th>Key</th><th>Switch To</th></tr></thead><tbody><tr><td><code>v</code></td><td>Character-wise</td></tr><tr><td><code>V</code></td><td>Line-wise</td></tr><tr><td><code>Ctrl+v</code></td><td>Block-wise</td></tr></tbody></table><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>V</code></td><td>Enter line-wise visual mode</td></tr><tr><td><code>d</code></td><td>Delete lines</td></tr><tr><td><code>y</code></td><td>Yank lines</td></tr><tr><td><code>&gt;</code></td><td>Indent right</td></tr><tr><td><code>&lt;</code></td><td>Indent left</td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li><code>V</code> selects whole lines.</li><li>Move with <code>j</code>/<code>k</code> to extend the selection.</li><li><code>d</code>, <code>y</code>, <code>c</code>, <code>&gt;</code>, <code>&lt;</code> all work on entire lines.</li><li>Switch between visual modes mid-selection.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open a file and select 5 lines with <code>V</code> and <code>j</code>.</li><li>Delete them with <code>d</code>.</li><li>Undo, then yank them with <code>y</code> and paste elsewhere.</li><li>Select lines and indent them with <code>&gt;</code>.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./24-visual-mode-block.html"><strong>Chapter 24 — Visual Mode: Block Selection</strong></a></p><p>Select rectangular blocks of text for column editing.</p>`,40)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
